import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.C24VBsJ9.js";const k=JSON.parse('{"title":"构建和部署实战指南","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/driver/00_chardev_base/11_build_test_deploy.md","filePath":"tutorial/driver/00_chardev_base/11_build_test_deploy.md","lastUpdated":1776495732000}'),l={name:"tutorial/driver/00_chardev_base/11_build_test_deploy.md"};function p(d,s,h,r,t,c){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="构建和部署实战指南" tabindex="-1">构建和部署实战指南 <a class="header-anchor" href="#构建和部署实战指南" aria-label="Permalink to &quot;构建和部署实战指南&quot;">​</a></h1><h2 id="前言-代码写完了-该让它跑起来了" tabindex="-1">前言：代码写完了，该让它跑起来了 <a class="header-anchor" href="#前言-代码写完了-该让它跑起来了" aria-label="Permalink to &quot;前言：代码写完了，该让它跑起来了&quot;">​</a></h2><p>前面几章我们花了很大篇幅讲硬件原理、内存映射机制、硬件抽象层设计和字符设备实现。说实话，光看这些理论真的很虚，代码不跑起来，永远不知道哪里会炸。现在到了最激动人心的时刻——把代码编译成模块，部署到开发板上，看着 LED 听从我们的指挥亮灭。</p><h2 id="第一步-理解-makefile-的结构" tabindex="-1">第一步：理解 Makefile 的结构 <a class="header-anchor" href="#第一步-理解-makefile-的结构" aria-label="Permalink to &quot;第一步：理解 Makefile 的结构&quot;">​</a></h2><p>在开始编译之前，我们先看看 Makefile 是怎么组织的。说实话，很多人（包括我们以前）都是直接复制粘贴 Makefile，改个文件名就开始编译，对里面到底发生了什么一知半解。这种做法在简单项目里可能没问题，但一旦出问题就两眼一抹黑。</p><p>我们先看第一部分：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Kernel module definition</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">obj-m := chardev_led_v1_01_driver.o</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chardev_led_v1_01_driver-y := chardev_led_v1_01_main.o led_hw.o</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这两行告诉内核构建系统：我们要编译一个模块叫 <code>chardev_led_v1_01_driver</code>，它由两个目标文件组成：<code>chardev_led_v1_01_main.o</code> 和 <code>led_hw.o</code>。注意这里 <code>.o</code> 后缀的文件名不要加 <code>.c</code>，构建系统会自动找到对应的 <code>.c</code> 文件。</p><p>这里有个细节很多人容易搞错：<code>obj-m</code> 里的 <code>m</code> 代表 module，意思是这是一个可加载模块。如果你写的是 <code>obj-y</code>，那这个代码会被直接编译进内核镜像，不能作为单独的 <code>.ko</code> 文件加载。对于我们这种开发阶段经常需要修改代码的场景，<code>obj-m</code> 是更合适的选择。</p><p>接下来是路径配置：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ── 项目配置 ────────────────────────────────────────</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROJECT_ROOT := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">shell</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> realpath $(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CURDIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/../..)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ARCH := arm</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CROSS_COMPILE := arm-none-linux-gnueabihf-</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 内核源码路径</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KDIR := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROJECT_ROOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/third_party/linux-</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KERNEL_TYPE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KOBJ := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROJECT_ROOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/out/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KERNEL_TYPE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出目录</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OUTPUT_DIR := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROJECT_ROOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/out/driver_artifacts/chardev_led_v1_01/alpha-board</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这里定义了一些路径和架构配置。<code>ARCH</code> 指定目标架构是 ARM，<code>CROSS_COMPILE</code> 指定交叉编译工具链前缀。这两个参数非常重要，如果填错了，编译出来的模块要么跑不起来，要么直接炸掉。</p><p><code>KDIR</code> 指向内核源码目录，<code>KOBJ</code> 是内核编译输出目录。为什么要分开这两个？因为内核编译会在源码目录下生成大量中间文件，如果你直接在源码目录里编译，会把源码目录弄得很乱。通过 <code>O</code> 参数指定一个独立的输出目录，可以保持源码目录的干净。</p><p>最后是编译规则：</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">modules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	@</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mkdir -p </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OUTPUT_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">	$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MAKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> -C </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KDIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> M=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">CURDIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> O=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KOBJ</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">		ARCH=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ARCH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CROSS_COMPILE=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CROSS_COMPILE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> modules</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	@</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cp *.ko </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">$(</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OUTPUT_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/ 2&gt;/dev/null || true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这一段是核心。<code>-C $(KDIR)</code> 切换到内核源码目录，<code>M=$(CURDIR)</code> 告诉内核构建系统我们的模块源码在哪里，<code>O=$(KOBJ)</code> 指定输出目录。最后把生成的 <code>.ko</code> 文件拷贝到我们的输出目录。</p><p>理解了这些，当编译出问题的时候，你就知道该去哪里找原因了。</p><h2 id="第二步-编译驱动模块" tabindex="-1">第二步：编译驱动模块 <a class="header-anchor" href="#第二步-编译驱动模块" aria-label="Permalink to &quot;第二步：编译驱动模块&quot;">​</a></h2><p>我们的项目提供了构建脚本，使用起来比直接调用 <code>make</code> 更方便。你可能会问，为什么不直接用 <code>make</code>？因为脚本帮我们处理了一些繁琐的细节，比如检测内核类型、创建输出目录、拷贝文件等。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/charliechen/imx-forge</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/driver_helper/build_driver.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chardev_led_v1_01</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> alpha-board</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这条脚本会自动处理内核类型检测、编译、拷贝等操作。如果一切顺利，你会看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔨 编译chardev_led_v1_01驱动...</span></span>
<span class="line"><span>make[1]: Entering directory &#39;/home/charliechen/imx-forge/third_party/linux-mainline&#39;</span></span>
<span class="line"><span>  CC [M]  /home/charliechen/imx-forge/driver/chardev_led_v1_01/alpha-board/chardev_led_v1_01_main.o</span></span>
<span class="line"><span>  CC [M]  /home/charliechen/imx-forge/driver/chardev_led_v1_01/alpha-board/led_hw.o</span></span>
<span class="line"><span>  MODPOST /home/charliechen/imx-forge/driver/chardev_led_v1_01/alpha-board/Module.symvers</span></span>
<span class="line"><span>  CC [M]  /home/charliechen/imx-forge/driver/chardev_led_v1_01/alpha-board/chardev_led_v1_01_driver.mod.o</span></span>
<span class="line"><span>  LD [M]  /home/charliechen/imx-forge/driver/chardev_led_v1_01/alpha-board/chardev_led_v1_01_driver.ko</span></span>
<span class="line"><span>make[1]: Leaving directory &#39;/home/charliechen/imx-forge/third_party/linux-mainline&#39;</span></span>
<span class="line"><span>✓ 驱动编译完成: out/driver_artifacts/chardev_led_v1_01/alpha-board/chardev_led_v1_01_driver.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>但说实话，第一次编译很少能这么顺利。我们总结了一些常见的坑，希望能帮你节省点时间。</p><p><strong>第一个坑是找不到头文件。</strong> 这通常有几个原因：要么是 <code>#include</code> 路径写错了，要么是内核源码目录不完整，要么是你用的内核版本和目标板子不匹配。内核构建系统默认只会搜索内核源码目录下的 <code>include</code> 和架构相关的 <code>include</code>，如果你需要额外的头文件，需要在 Makefile 里用 <code>ccflags-y</code> 指定。</p><p><strong>第二个坑是内核版本不匹配。</strong> 内核模块对版本依赖非常严格，必须用和目标内核完全匹配的源码编译。如果你在板子上跑的是 <code>5.15.0</code>，但你编译模块用的是 <code>5.14.0</code> 的源码，加载的时候会提示 &quot;Invalid module format&quot;。这种情况下，唯一的解决办法就是找到匹配的内核源码重新编译。</p><p><strong>第三个坑是交叉编译工具链问题。</strong> 如果你的 <code>CROSS_COMPILE</code> 前缀不对，或者工具链不在 PATH 里，编译就会失败。一个简单的验证方法是直接运行 <code>arm-none-linux-gnueabihf-gcc -v</code>，看看能不能找到这个命令。</p><h2 id="第三步-部署到开发板" tabindex="-1">第三步：部署到开发板 <a class="header-anchor" href="#第三步-部署到开发板" aria-label="Permalink to &quot;第三步：部署到开发板&quot;">​</a></h2><p>编译成功后，<code>.ko</code> 文件位于 <code>out/driver_artifacts/chardev_led_v1_01/alpha-board/</code> 目录下。现在需要把它部署到开发板。</p><p>我们的项目提供了部署脚本：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/driver_helper/deploy_driver.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chardev_led_v1_01</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> alpha-board</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>对于现在咱们是NFS调试阶段，那就部署到NFS上就好。</p><h2 id="第四步-加载和测试驱动" tabindex="-1">第四步：加载和测试驱动 <a class="header-anchor" href="#第四步-加载和测试驱动" aria-label="Permalink to &quot;第四步：加载和测试驱动&quot;">​</a></h2><h3 id="加载驱动" tabindex="-1">加载驱动 <a class="header-anchor" href="#加载驱动" aria-label="Permalink to &quot;加载驱动&quot;">​</a></h3><p>登录到开发板，进入存放 <code>.ko</code> 文件的目录，执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">insmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chardev_led_v1_01_driver.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果成功，不会有任何输出。这是 Linux 的哲学：没有消息就是好消息。但如果你是个强迫症患者，可以用 <code>lsmod</code> 检查：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chardev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该能看到 <code>chardev_led_v1_01_driver</code> 在列表里。</p><h3 id="查看内核日志" tabindex="-1">查看内核日志 <a class="header-anchor" href="#查看内核日志" aria-label="Permalink to &quot;查看内核日志&quot;">​</a></h3><p>驱动加载时会打印一些初始化信息，我们可以用 <code>dmesg</code> 查看：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dmesg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该能看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ 1234.567890] IMX6U_CCM_CCGR1    = 0xf5d1000 (phys: 0x20c406c)</span></span>
<span class="line"><span>[ 1234.567891] SW_MUX_GPIO1_IO03  = 0xf5d2000 (phys: 0x20e0068)</span></span>
<span class="line"><span>[ 1234.567892] SW_PAD_GPIO1_IO03  = 0xf5d3000 (phys: 0x20e02f4)</span></span>
<span class="line"><span>[ 1234.567893] GPIO1_DR           = 0xf5d4000 (phys: 0x209c000)</span></span>
<span class="line"><span>[ 1234.567894] GPIO1_GDIR         = 0xf5d5000 (phys: 0x209c004)</span></span>
<span class="line"><span>[ 1234.567895] CCGR1 raw value: 0x00000000</span></span>
<span class="line"><span>[ 1234.567896] CCGR1 new raw value: 0x0c000000</span></span>
<span class="line"><span>[ 1234.567897] Setting SW_MUX_GPIO1_IO03 = 0x5</span></span>
<span class="line"><span>[ 1234.567898] GPIO1_GDIR set to 0x00000008</span></span>
<span class="line"><span>[ 1234.567899] GPIO1_DR init set to 0x00000008 (LED OFF)</span></span>
<span class="line"><span>[ 1234.567900] LED Init OK!</span></span>
<span class="line"><span>[ 1234.567901] AES_LED load successfully!</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>这些日志告诉我们硬件初始化的每一步都成功了。从 CCM 时钟寄存器到 GPIO 复用、_pad 配置、方向设置，每一步都有对应的打印。这种调试信息在开发阶段非常宝贵，能帮你快速定位问题。</p><h3 id="创建设备节点" tabindex="-1">创建设备节点 <a class="header-anchor" href="#创建设备节点" aria-label="Permalink to &quot;创建设备节点&quot;">​</a></h3><p>驱动加载成功后，还需要创建设备节点才能被用户空间访问。对于使用老 API 的驱动，这一步是必须的：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mknod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条命令创建一个字符设备文件（<code>c</code>），主设备号 200，次设备号 0。主设备号必须和驱动里注册的一致（<code>CHARDEV_MAJOR = 200</code>）。</p><p>你还可以调整权限，让非 root 用户也能访问：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chmod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 666</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>说实话，每次加载驱动后都要手动执行这些命令真的很烦。这也是为什么新 API 引入了自动创建设备节点的机制，但我们后面再讲这个。</p><h3 id="测试-led-控制" tabindex="-1">测试 LED 控制 <a class="header-anchor" href="#测试-led-控制" aria-label="Permalink to &quot;测试 LED 控制&quot;">​</a></h3><p>现在可以开始测试了：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 点亮 LED</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 熄灭 LED</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;0&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查询状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>如果一切正常，你会看到 LED 随着命令亮灭，<code>cat /dev/led</code> 会输出 <code>&#39;1&#39;</code> 或 <code>&#39;0&#39;</code> 表示当前状态。到这一刻，恭喜你，你的第一个字符设备驱动成功运行了！</p><h2 id="第五步-排查常见问题" tabindex="-1">第五步：排查常见问题 <a class="header-anchor" href="#第五步-排查常见问题" aria-label="Permalink to &quot;第五步：排查常见问题&quot;">​</a></h2><p>我们在折腾过程中遇到过各种问题，这里挑一些比较有代表性的分享一下。</p><h3 id="insmod-提示-invalid-module-format" tabindex="-1">insmod 提示 &quot;Invalid module format&quot; <a class="header-anchor" href="#insmod-提示-invalid-module-format" aria-label="Permalink to &quot;insmod 提示 &quot;Invalid module format&quot;&quot;">​</a></h3><p>这通常意味着模块版本和内核版本不匹配。内核模块对版本依赖非常严格，必须用和目标内核完全匹配的源码编译。解决方法：确认 <code>KDIR</code> 指向的内核源码和开发板运行的内核版本一致。你可以用 <code>uname -r</code> 在板子上查看内核版本，然后在主机上确认源码目录的版本。</p><h3 id="insmod-时出现-unknown-symbol" tabindex="-1">insmod 时出现 &quot;Unknown symbol&quot; <a class="header-anchor" href="#insmod-时出现-unknown-symbol" aria-label="Permalink to &quot;insmod 时出现 &quot;Unknown symbol&quot;&quot;">​</a></h3><p>这是因为驱动依赖的某个符号（函数或变量）在当前内核配置下没有被编译进去。检查 <code>dmesg</code> 输出，看具体是哪个符号找不到。如果是你自己在代码里调用了一个不存在的函数，需要换一个实现方式。</p><p>我们遇到过一次，驱动里用了 <code>gpio_set_value</code>，但内核配置没开启 GPIO 支持，结果加载时就报这个错。这种情况下，要么改内核配置重新编译内核，要么换一种方式控制 GPIO。</p><h3 id="led-不亮也不灭" tabindex="-1">LED 不亮也不灭 <a class="header-anchor" href="#led-不亮也不灭" aria-label="Permalink to &quot;LED 不亮也不灭&quot;">​</a></h3><p>这个问题可能的原因就多了。首先确认硬件连接没问题（LED 正确接到 GPIO1_IO03），然后用 <code>dmesg</code> 查看驱动日志，看初始化是否成功。检查寄存器地址是否正确，时钟是否开启，引脚复用是否配置正确。</p><p>一个有用的调试技巧是在 <code>led_set_status()</code> 里多加一些打印，看看函数是否被调用，寄存器读写是否成功。有时候你以为代码没问题，但实际跑起来跟你想象的不一样。</p><h3 id="rmmod-时卡住或报错" tabindex="-1">rmmod 时卡住或报错 <a class="header-anchor" href="#rmmod-时卡住或报错" aria-label="Permalink to &quot;rmmod 时卡住或报错&quot;">​</a></h3><p>这通常意味着有进程还在使用设备。检查是否有程序打开着 <code>/dev/led</code> 没有关闭，或者是否有后台进程在访问设备。用 <code>lsof /dev/led</code> 可以查看哪些进程在占用设备。</p><p>我们遇到过一次，测试程序异常退出了，但没有正确关闭文件描述符，导致 <code>rmmod</code> 一直卡住。最后只能 <code>kill -9</code> 杀掉那个进程，然后才能卸载驱动。</p><h2 id="第六步-性能考虑-暂时不用太在意" tabindex="-1">第六步：性能考虑（暂时不用太在意） <a class="header-anchor" href="#第六步-性能考虑-暂时不用太在意" aria-label="Permalink to &quot;第六步：性能考虑（暂时不用太在意）&quot;">​</a></h2><p>对于 LED 控制这种简单功能，性能基本不是问题。但如果你的驱动需要频繁操作寄存器，有一些优化技巧值得了解。</p><p>第一个是减少寄存器访问次数。如果可能，把多次读写合并成一次。比如配置多个位时，先构造好完整的值，一次性写进去，而不是每配置一个位就写一次。</p><p>第二个是考虑使用缓存。如果频繁读取同一个寄存器，可以在驱动里缓存它的值，避免重复读取。但要注意缓存一致性——如果寄存器值可能被硬件改变，缓存就会失效。</p><p>第三个是避免频繁的用户态/内核态切换。如果需要连续执行多个操作，考虑实现一个 <code>ioctl</code> 接口，一次性完成所有操作，而不是多次 <code>write()</code> 调用。</p><p>对于我们的 LED 驱动，这些优化都不必要，因为控制频率很低。但了解这些原则对以后开发更复杂的驱动有帮助。</p><h2 id="卸载驱动" tabindex="-1">卸载驱动 <a class="header-anchor" href="#卸载驱动" aria-label="Permalink to &quot;卸载驱动&quot;">​</a></h2><p>测试完成后，记得清理：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rmmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chardev_led_v1_01_driver</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/led</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>rmmod</code> 会调用驱动的 <code>exit</code> 函数，清理硬件资源和注销设备。你应该能在 <code>dmesg</code> 里看到类似这样的输出：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ 2345.678901] === chardev_led_v1_01 rmmod progress ===</span></span>
<span class="line"><span>[ 2345.678902] Deinit the LED Hardware</span></span>
<span class="line"><span>[ 2345.678903] ========================</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>到这里，我们已经完成了从硬件理解到驱动实现，再到编译部署的完整流程。你掌握的不仅仅是一个 LED 驱动，更是一套可以复用到其他驱动的开发流程和方法论。</p><p>回顾一下，我们学到了什么：</p><p>第一，理解 Makefile 的结构很重要。不要只是复制粘贴，知道每个参数的作用，出问题的时候才能快速定位。</p><p>第二，编译过程可能会遇到各种坑，大多数是路径、版本、工具链相关的问题。耐心排查，这些问题都有明确的解决方案。</p><p>第三，部署和测试是验证代码正确性的关键步骤。内核日志是你的好朋友，多打印信息能帮你快速定位问题。</p><p>下一步，你可以尝试修改代码，实现更复杂的功能。比如支持亮度调节（PWM）、支持闪烁模式、通过 ioctl 实现更多控制命令。或者，你可以去看看新 API 的实现，了解现代字符设备驱动的标准写法。</p><p>驱动开发的大门已经打开了，接下来就是不断实践和探索了。祝你在内核驱动的世界里玩得开心！</p><p><strong>相关文档</strong>：</p><ul><li><a href="./06_legacy_chardev">老 API 字符设备驱动</a></li><li><a href="./12_new_chardev_api_overview">新字符设备驱动 API 概览</a></li><li><a href="./04_kernel_print_guide">内核打印调试指南</a></li></ul>`,89)])])}const b=a(l,[["render",p]]);export{k as __pageData,b as default};
